def get_hip_version():
    rocm_path = os.environ.get("ROCM_PATH", "/opt/rocm")
    hipconfig_path = os.path.join(rocm_path, "bin", "hipconfig")
    version = subprocess.run(
        f"{hipconfig_path} --version", shell=True, capture_output=True, text=True
    )
    return parse(version.stdout.split()[-1].rstrip("-").replace("-", "+"))
